sparql:
PREFIX foaf: <http://xmlns.com/foaf/0.1/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?work WHERE { ?work efrbroo:R8_consists_of ?instrument . ?instrument foaf:name 'flute' }

PREFIX ecrm: <http://erlangen-crm.org/current/>
PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
SELECT ?concert WHERE { ?concert ecrm:P14_carried_out_by ?violinist . ?concert ecrm:P9_consists_of ?work . ?work efrbroo:R17_created ?composer . }

PREFIX efrbroo: <http://erlangen-crm.org/efrbroo/>
PREFIX dct: <http://purl.org/dc/terms/>
SELECT ?expression WHERE { ?expression efrbroo:R22_created ?work . ?work dct:creator ?lyricist . }
